import {
  computed,
  effect,
  inject,
  Injectable,
  signal,
  untracked,
} from '@angular/core';
import {
  AccountsService,
  AuthUserResponse,
  ClientMeasurementUnits,
  ClientResponse,
} from '../../../api';
import {
  APP_FEATURE_FLAGS,
  AppFeatureDefaults,
  AppFeatureDefaultsStructure,
  BACKEND_FEATURE_FLAGS,
  BackendFeatureDefaults,
  LOCAL_STORAGE_KEY_SELECTED_CLIENT,
} from '../../../core/models';
import { LocalStorageService } from '../../../shared/services/local-storage.service';
import { cloneDeep, set, get } from 'lodash';
import { isDefined, isEmpty, isNullOrUndefined } from '../../../shared/utils';
import { UnitPreferences, MeasurementUnitType } from '../../../shared/models';
import { MeasurementUnitsService } from '../../../shared/services/measurement-units/measurement-units.service';
import { ActivatedRouteSnapshot, Router } from '@angular/router';
import { UserSessionService } from '../../../core/services/user-session.service';
import { toObservable } from '@angular/core/rxjs-interop';
import {
  distinctUntilChanged,
  switchMap,
  catchError,
  of,
  combineLatest,
  filter,
  firstValueFrom,
} from 'rxjs';
import { RequestCacheService } from '../../../shared/services/request-cache.service';

@Injectable({
  providedIn: 'root',
})
export class ClientDataService {
  private readonly selectedClient = signal<Partial<ClientResponse> | null>(
    null,
  );
  private readonly features = signal({
    ...AppFeatureDefaults,
    ...BackendFeatureDefaults,
  });
  private readonly localStorageService = inject(LocalStorageService);
  private cachedFeatures: {
    clientId: string | null;
    features: AppFeatureDefaultsStructure;
    flagsSignature: string | null;
  } | null = null;
  private readonly measurementUnitsService = inject(MeasurementUnitsService);
  private readonly router = inject(Router);
  // Tracks whether initial client loading attempt (restore/fetch) is complete
  private readonly initializationCompleted = signal(false);
  private readonly userSessionService = inject(UserSessionService);
  private readonly accountsService = inject(AccountsService);
  private readonly requestCacheService = inject(RequestCacheService);

  // Computed signal that extracts just the client ID for effect tracking
  private readonly selectedClientId = computed(
    () => this.selectedClient()?.id ?? null,
  );

  constructor() {
    // Listen to both user ID and session changes
    combineLatest([
      toObservable(this.localStorageService.getCurrentUserIdSignal()),
      toObservable(this.userSessionService.currentUserSession),
    ])
      .pipe(
        // Only proceed when we have a user ID
        filter(
          ([userId, userSession]) => userId !== null && isDefined(userSession),
        ),
        distinctUntilChanged(
          ([prevUserId, prevSession], [currUserId, currSession]) =>
            prevUserId === currUserId &&
            prevSession?.defaultClient?.id === currSession?.defaultClient?.id,
        ),
        switchMap(([_userId, session]) => {
          // Try to restore persisted client first (now with correct namespace!)
          const persistedClient = this.localStorageService.getItem<
            Partial<ClientResponse>
          >(LOCAL_STORAGE_KEY_SELECTED_CLIENT, true);

          if (isDefined(persistedClient?.id)) {
            return this.accountsService.getClient(persistedClient.id).pipe(
              catchError((error) => {
                console.warn(
                  'Failed to load persisted client, falling back to default',
                  error,
                );
                return this.loadDefaultClient(session);
              }),
            );
          }

          return this.loadDefaultClient(session);
        }),
      )
      .subscribe({
        next: (client) => {
          if (isDefined(client)) {
            this.setSelectedClient(client);
          } else {
            this.clearSelectedClient();
          }
          this.markInitializationComplete();
        },
        error: () => {
          this.clearSelectedClient();
          this.markInitializationComplete();
        },
      });

    // Track only client ID changes to prevent double-firing when incomplete -> complete transition happens
    effect(() => {
      this.selectedClientId();

      // Use untracked to prevent tracking other client properties
      untracked(() => {
        const client = this.selectedClient();
        // If client is incomplete, fetch complete data in background
        if (
          isDefined(client) &&
          !this.isCompleteClientData(client) &&
          isDefined(client.id)
        ) {
          this.ensureCompleteClientData(client.id).catch((error) => {
            console.error('Failed to ensure complete client data:', error);
          });
        } else {
          // Only get features if client is complete or null
          this.getFeaturesForClient();
        }
      });
    });
  }

  /**
   * Checks if a client object has all required fields for feature evaluation
   */
  private isCompleteClientData(client: Partial<ClientResponse>): boolean {
    // Check for critical fields needed for features
    return (
      isDefined(client.id) &&
      isDefined(client.name) &&
      isDefined(client.meta) &&
      isDefined(client.flags)
    );
  }

  /**
   * Fetches complete client data from API with caching to prevent duplicate requests.
   * Uses a short TTL to ensure fresh data while avoiding redundant API calls.
   * @param clientId The client ID to fetch
   * @returns Observable of complete client data
   */
  fetchClientWithCache(clientId: string) {
    const cacheKey = `client-${clientId}`;
    return this.requestCacheService.getOrFetch(
      cacheKey,
      () => this.accountsService.getClient(clientId),
      2000, // 2 second TTL to prevent duplicate requests during tree building
    );
  }

  /**
   * Ensures the client has complete data by fetching from API if needed.
   * Uses caching to prevent duplicate requests.
   */
  private async ensureCompleteClientData(clientId: string): Promise<void> {
    try {
      const completeClient = await firstValueFrom(
        this.fetchClientWithCache(clientId),
      );

      // Only update if this is still the current client and it's incomplete
      const currentClient = this.selectedClient();
      if (
        currentClient?.id === clientId &&
        !this.isCompleteClientData(currentClient)
      ) {
        this.setSelectedClient(completeClient);
      }
    } catch (error) {
      console.error('Failed to fetch complete client data:', error);
      // Continue with incomplete data rather than blocking
      this.getFeaturesForClient();
    }
  }

  /**
   * Load the default client from the user session
   */
  private loadDefaultClient(session: AuthUserResponse | null) {
    const clientId = session?.defaultClient?.id;

    if (!isDefined(clientId)) {
      return of(null);
    }

    return this.accountsService.getClient(clientId).pipe(
      catchError(() => {
        console.warn('Failed to load default client');
        return of(null);
      }),
    );
  }

  /**
   * Mark that initial client initialization has completed (success or not).
   * Guards waiting on readiness can then proceed.
   */
  markInitializationComplete(): void {
    if (!this.initializationCompleted()) {
      this.initializationCompleted.set(true);
    }
  }

  /**
   * Returns true when feature evaluation can happen (client selected or init finished)
   */
  isFeatureEvaluationReady(): boolean {
    return !!this.selectedClient() || this.initializationCompleted();
  }

  /**
   * Wait for readiness (with timeout) before resolving.
   */
  waitForFeatureReadiness(timeoutMs = 4000): Promise<boolean> {
    if (this.isFeatureEvaluationReady()) return Promise.resolve(true);
    return new Promise((resolve) => {
      let completed = false;
      const ref = effect(() => {
        if (this.isFeatureEvaluationReady() && !completed) {
          completed = true;
          resolve(true);
          ref.destroy();
        }
      });
      setTimeout(() => {
        if (!completed) {
          completed = true;
          resolve(false); // timed out, proceed anyway
          ref.destroy();
        }
      }, timeoutMs);
    });
  }

  /**
   * Sets the selected client by ID, ensuring complete data is fetched.
   * This is the preferred method when you only have a client ID.
   * @param clientId The client ID to fetch and set
   */
  async setSelectedClientById(clientId: string): Promise<void> {
    try {
      const completeClient = await firstValueFrom(
        this.fetchClientWithCache(clientId),
      );
      this.setSelectedClient(completeClient);
    } catch (error) {
      console.error('Failed to fetch and set client:', error);
      throw error;
    }
  }

  /**
   * Sets the selected client and stores it in localStorage.
   * This persists across page refreshes and logout/login cycles.
   * @param client The client to be selected.
   */
  setSelectedClient(client: Partial<ClientResponse>): void {
    const selectedClientData = {
      customFields: client?.customFields,
      id: client.id,
      flags: client?.flags,
      name: client.name,
      measurementUnits: client?.measurementUnits,
      owner: client?.owner,
      theme: client?.theme,
      mapSet: client?.mapSet,
      group: client?.group,
      meta: client?.meta,
      availableDeviceTypes: client?.availableDeviceTypes,
    };

    this.selectedClient.set(selectedClientData);
    this.localStorageService.setItem(
      LOCAL_STORAGE_KEY_SELECTED_CLIENT,
      selectedClientData,
      undefined,
      true,
    );
    this.cachedFeatures = null;
    this.updateMeasurementUnits(client);
  }

  /**
   * Retrieves the selected client.
   * @returns The selected client.
   */
  getSelectedClient(): Partial<ClientResponse> | null {
    return this.selectedClient();
  }

  /**
   * Retrieves the selected client as a signal.
   * @returns The selected client signal.
   */
  getSelectedClientSignal() {
    return this.selectedClient;
  }

  /**
   * Clears the selected client and removes it from localStorage.
   */
  clearSelectedClient(): void {
    const clientId = this.selectedClient()?.id;
    this.selectedClient.set(null);
    this.updateMeasurementUnits(null);
    this.localStorageService.removeItem(
      LOCAL_STORAGE_KEY_SELECTED_CLIENT,
      true,
    );
    // Clear the cache for this client
    if (isDefined(clientId)) {
      this.requestCacheService.clearCache(`client-${clientId}`);
    }
  }

  /**
   * Clears only the selected client signal without affecting localStorage.
   * Useful for temporary client deselection (e.g., during logout).
   */
  clearSelectedClientSignal(): void {
    this.selectedClient.set(null);
  }

  /**
   * Retrieves feature flags for the selected client, merging default values
   * with any client-specific overrides.
   * @returns A merged object containing both app and backend feature flags
   */
  getFeaturesForClient(): AppFeatureDefaultsStructure {
    const client = this.selectedClient();
    const clientId = client?.id ?? null;
    // Consider using mergedFlags for signature if available
    const flagsSignature = this.getFlagsSignature(client?.flags);

    const defaultFeatures = {
      ...AppFeatureDefaults,
      ...BackendFeatureDefaults,
    };

    let result: AppFeatureDefaultsStructure;

    if (
      this.cachedFeatures?.clientId === clientId &&
      this.cachedFeatures?.flagsSignature === flagsSignature
    ) {
      result = this.cachedFeatures.features;
    } else if (isNullOrUndefined(client)) {
      result = cloneDeep(defaultFeatures);
      this.cachedFeatures = {
        clientId,
        features: result,
        flagsSignature: null,
      };
    } else {
      // Clone default features as the base for client-specific settings
      result = cloneDeep(defaultFeatures);
      const flags = client?.meta?.mergedFlags ?? {};

      // Process app feature flags
      const appFlags = flags[APP_FEATURE_FLAGS] ?? {};
      for (const [id, value] of Object.entries(appFlags)) {
        this.setFeatureFlag(result, id, value);
      }

      // Process backend feature flags
      const backendFlags = flags[BACKEND_FEATURE_FLAGS] ?? {};
      for (const [id, value] of Object.entries(backendFlags)) {
        this.setFeatureFlag(result, id, value);
      }

      // Cache fresh result
      this.cachedFeatures = { clientId, features: result, flagsSignature };
    }

    // Apply once
    this.features.set(result);
    this.enforceActiveRouteAccess(result);
    return result;
  }

  // Helper to create a stable signature for caching
  private getFlagsSignature(flags: unknown): string | null {
    if (isNullOrUndefined(flags)) return null;
    try {
      return JSON.stringify(flags);
    } catch {
      return null;
    }
  }

  /**
   * Helper method to safely set a feature flag value
   * @param target Object to update
   * @param path Path to the property (with hyphens)
   * @param value Value to set
   */
  private setFeatureFlag(
    target: AppFeatureDefaultsStructure,
    path: string,
    value: unknown,
  ): void {
    try {
      const normalizedPath = path.replaceAll('-', '.');
      set(target, normalizedPath, value);
    } catch (err) {
      console.warn(`Error setting feature flag at path ${path}:`, err);
    }
  }

  // Enforce that the currently active route is accessible with the latest features
  private enforceActiveRouteAccess(
    features: AppFeatureDefaultsStructure,
  ): void {
    try {
      const data = this.findFeatureFlagInSnapshot(
        this.router.routerState.snapshot.root,
      );
      if (!data) return;

      const allowed = this.isAllowedByFlags(
        features,
        data.flag,
        data.requireAll,
      );
      if (!allowed) {
        // Redirect to root (which routes to Position)
        void this.router.navigateByUrl('/', { replaceUrl: true });
      }
    } catch {
      // no-op
    }
  }

  private findFeatureFlagInSnapshot(
    root: ActivatedRouteSnapshot,
  ): { flag: string | string[]; requireAll: boolean } | null {
    // find deepest activated route
    let deepest: ActivatedRouteSnapshot = root;
    while (deepest.firstChild) deepest = deepest.firstChild;

    // check upwards for any featureFlag on route data
    let current: ActivatedRouteSnapshot | null = deepest;
    while (current) {
      const data = current.data ?? {};
      const flag = data['featureFlag'] as string | string[] | undefined;
      if (flag !== undefined) {
        const requireAll = (data['requireAll'] as boolean | undefined) ?? true;
        return { flag, requireAll };
      }
      current = current.parent ?? null;
    }
    return null;
  }

  private isAllowedByFlags(
    features: AppFeatureDefaultsStructure,
    flag: string | string[],
    requireAll: boolean,
  ): boolean {
    const evaluate = (path: string): boolean =>
      Boolean(get(features as object, path));
    return Array.isArray(flag)
      ? requireAll
        ? flag.every(evaluate)
        : flag.some(evaluate)
      : evaluate(flag);
  }

  /**
   * Retrieves the features signal.
   */
  getFeaturesSignal() {
    return this.features;
  }

  /**
   * Updates measurement units based on client preferences
   * @param client - The client with measurement preferences
   */
  private mapClientUnitsToPreferences(
    clientUnits: ClientMeasurementUnits,
  ): Partial<UnitPreferences> {
    const unitPreferences: Partial<UnitPreferences> = {};
    const unitMappings = [
      {
        type: MeasurementUnitType.DISTANCE,
        value: clientUnits.distanceUnit,
        key: 'distanceUnit',
      },
      {
        type: MeasurementUnitType.ALTITUDE,
        value: clientUnits.altitudeUnit,
        key: 'altitudeUnit',
      },
      {
        type: MeasurementUnitType.AREA,
        value: clientUnits.areaUnit,
        key: 'areaUnit',
      },
      {
        type: MeasurementUnitType.SPEED,
        value: clientUnits.speedUnit,
        key: 'speedUnit',
      },
      {
        type: MeasurementUnitType.TEMPERATURE,
        value: clientUnits.temperatureUnit,
        key: 'temperatureUnit',
      },
      {
        type: MeasurementUnitType.WEIGHT,
        value: clientUnits.weightUnit,
        key: 'weightUnit',
      },
      {
        type: MeasurementUnitType.VOLUME,
        value: clientUnits.volumeUnit,
        key: 'volumeUnit',
      },
      {
        type: MeasurementUnitType.DATE,
        value: clientUnits.dateUnit,
        key: 'dateUnit',
      },
      {
        type: MeasurementUnitType.TIME,
        value: clientUnits.timeUnit,
        key: 'timeUnit',
      },
    ];

    for (const { type, value, key } of unitMappings) {
      if (isDefined(value) && this.isValidUnitValue(type, value)) {
        unitPreferences[key as keyof UnitPreferences] = value;
      }
    }

    return unitPreferences;
  }

  /**
   * Updates measurement units in the service based on client data
   * @param client - The client response object
   */
  // This method is called when the selected client changes
  // It updates the measurement units in the service based on the client's preferences
  // If the client has no measurement units, it resets to defaults
  private updateMeasurementUnits(client: Partial<ClientResponse> | null): void {
    if (isEmpty(client?.measurementUnits)) {
      this.measurementUnitsService.resetToDefaults();
      return;
    }

    const clientUnits: ClientMeasurementUnits = client?.measurementUnits ?? {};
    const unitPreferences = this.mapClientUnitsToPreferences(clientUnits);
    this.measurementUnitsService.updatePartialConfig(unitPreferences);
  }

  private isValidUnitValue(type: MeasurementUnitType, value: string): boolean {
    return this.measurementUnitsService.isValidUnitValue(type, value);
  }
}
